const UVT      = { x: W / 2 - 50,   y: H / 2 + 580 };
const EXTERNAL = { x: W / 2 + 20,   y: H / 2 - 20 };

// Helper: evenly distribute nodes around a center point in a circle
function ring(center, count, radius, startAngle = -Math.PI / 2) {
  return Array.from({ length: count }, (_, i) => {
    const angle = startAngle + (2 * Math.PI * i) / count;
    return {
      x: Math.round(center.x + radius * Math.cos(angle)),
      y: Math.round(center.y + radius * Math.sin(angle)),
    };
  });
}

