    activities: { theory: "SHAP values, LIME, attention visualization, mechanistic interpretability.", experiment: "XAI benchmark suites, human-in-the-loop evaluation of explanations.", design: "XAION platform, SHAP/LIME libraries, interpretable model wrappers." },
    people: ["Judea Pearl", "Yoshua Bengio", "Geoffrey Hinton"],
    problems: [], venues: ["NeurIPS", "ICML", "AAAI"],
